## Watchdog ile Dosya İzleme
```python
from watchdog.observers import Observer
from watchdog.events import FileSystemEventHandler
import time

class AutoHandler(FileSystemEventHandler):
    def on_created(self, event):
        if event.src_path.endswith('.csv'):
            print(f'Yeni CSV: {event.src_path}')
            process_csv(event.src_path)

    def on_modified(self, event):
        if not event.is_directory:
            print(f'Değişti: {event.src_path}')

observer = Observer()
observer.schedule(AutoHandler(), '/watched/folder', recursive=True)
observer.start()
try:
    while True: time.sleep(1)
finally:
    observer.stop()
    observer.join()
```
